export function claimOffice(request: any): any {
  const items = request.steps[0].items;
  let basePremium = 0;
  for (const item of items) {
    basePremium += BASE_PREMIUMS[item.type];
  }
  return [{ premium: basePremium + PROCESSING_FEE }];
}

